// Product interface (duck-typed)
class Transport {
  deliver() {
    throw new Error('deliver() must be implemented');
  }
}

// Concrete Products
class Truck extends Transport {
  deliver() {
    return 'Deliver by land in a box';
  }
}

class Ship extends Transport {
  deliver() {
    return 'Deliver by sea in a container';
  }
}

// Creator
class Logistics {
  // Factory method
  createTransport() {
    throw new Error('createTransport() must be implemented');
  }

  planDelivery() {
    const transport = this.createTransport();
    return `Planning: ${transport.deliver()}`;
  }
}

// Concrete Creators
class RoadLogistics extends Logistics {
  createTransport() {
    return new Truck();
  }
}

class SeaLogistics extends Logistics {
  createTransport() {
    return new Ship();
  }
}

// Usage
const road = new RoadLogistics();
console.log(road.planDelivery()); // Planning: Deliver by land in a box

const sea = new SeaLogistics();
console.log(sea.planDelivery());  // Planning: Deliver by sea in a container

